 in 2:length(species_names)){ for (j in 1:(i - 1)){ pair_names &lt;- c(pair_names, paste(species_names[i], species_names[j], sep = &quot; - &quot;)) phylo_vals &lt;- c(phylo_vals, phylo_dist[i, j]) overlap_vals &lt;- c(overlap_vals, overlap_matrix[i, j]) } } # Fit a linear regression between phylogenetic distance and niche overlap. lm_res &lt;- lm(overlap_vals ~ phylo_vals) s &lt;- summary(lm_res) print(s) # Format regression statistics for display on the plot. label_text &lt;- paste0(&quot;Intercept = &quot;, format(round(coef(lm_res)[1], 3)), &quot;
